import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

// Webhook handler
export async function handleAssistantCompletion(event: any) {
  const messages = await openai.beta.threads.messages.list(event.thread_id);
  const extraction = JSON.parse(messages.data[0].content[0].text.value);

  const result = await vex.verify({
    name: 'invoice-extraction-v2',
    input: extraction,
    rules: [
      vex.jsonSchema(invoiceSchema),
      vex.fieldRequired('invoice_number'),
      vex.fieldRequired('total'),
      vex.type('total', 'number'),
      vex.pattern('invoice_number', '^[A-Z]{2}-\\d{6}$'),
      vex.greaterThan('total', 0),
      vex.fieldLength('vendor', { min: 2, max: 100 })
    ]
  });

  if (result.passed) {
    console.log('✅ Extraction verified:', extraction);
  } else {
    console.error('❌ Verification failed:', result.failures);
  }
}

